# --- Custom APM Transaction for Background Tasks ---
class BackgroundTaskTracker:
    """Helper class to track background tasks in APM."""
    
    def __init__(self, task_name, task_type='background'):
        self.task_name = task_name
        self.task_type = task_type
        self.client = None
    
    def __enter__(self):
        self.client = elasticapm.get_client()
        if self.client:
            self.client.begin_transaction(self.task_type)
            elasticapm.label(task_name=self.task_name)
        return self
    
    def __exit__(self, exc_type, exc_val, exc_tb):
        if self.client:
            if exc_type:
                self.client.capture_exception()
                result = 'failure'
            else:
                result = 'success'
            self.client.end_transaction(self.task_name, result)
        return False


def run_background_task_example():
    """Example of tracking a background task."""
    with BackgroundTaskTracker('data_cleanup') as tracker:
        logger.info("Running background data cleanup task")
        time.sleep(0.5)
